import json, sys
sys.stdout.reconfigure\(encoding='utf-8'\)
with open\('full-final-pipeline.ipynb', 'r', encoding='utf-8'\) as f:
    nb = json.load\(f\)

for i, cell in enumerate\(nb['cells']\):
    if cell['cell_type'] != 'code':
        continue
    outputs = cell.get\('outputs', []\)
    if not outputs:
        continue
    print\(f'===== CELL {i} OUTPUTS ====='\)
    for out in outputs:
        otype = out.get\('output_type', ''\)
        if otype == 'stream':
            text = ''.join\(out.get\('text', []\)\)
            print\(text[:3000]\)
        elif otype == 'execute_result':
            text = ''.join\(out.get\('data', {}\).get\('text/plain', []\)\)
            print\(text[:1000]\)
        elif otype == 'display_data':
            if 'image/png' in out.get\('data', {}\):
                print\('[IMAGE/PLOT OUTPUT]'\)
            else:
                text = ''.join\(out.get\('data', {}\).get\('text/plain', []\)\)
                print\(text[:500]\)
        elif otype == 'error':
            ename = out.get\('ename', ''\)
            evalue = out.get\('evalue', ''\)
            print\(f'ERROR: {ename}: {evalue}'\)
    print\(\)
PYEOF)
